    ...PROMOTION_CATALOG.map((o,i)=>({...o,id:`promotion-${i}`,type:'promotion',taxType:'taxExclusive',provider:'PCSAPO マキシ企画',url:'',checkedAt:'',customerVisible:true,quoteEnabled:true,sortOrder:500+i,notes:'最低受注額10,000円。交通費・駐車場・送料・印刷費・施設利用料は別途。',active:true})),
