function customerHomePage(){const items=[['website','ホームページ制作','STUDIOを使った店舗サイト制作、公開、更新方法まで支援します。'],['square','Square導入','店頭決済、レストランメニュー登録、テイクアウト・ECの初期構築を支援します。'],['funfo','funfo構築','QRセルフオーダーをFreeから試し、必要に応じてハンディ・厨房印刷へ拡張します。'],['designService','制作・販促支援','メニュー、名刺、チラシの制作から、合意した範囲の設置支援まで対応します。']];return `${pageHead('01','店舗導入パッケージ','Restaurant Implementation Package','必要なサービスを選び、詳しい内容と費用をご確認いただけます。')}<section class="customer-lead"><div><span>PCSAPO マキシ企画</span><h2>店舗に合うサービスを、一緒に選びます。</h2><p>特定メーカーの商品を販売する立場ではなく、費用・機能・現場運用を比較してご提案します。</p></div><button class="button ghost" data-go="position">私たちの役割を確認</button></section><div class="grid two service-link-grid">${items.map(([id,title,desc],i)=>`<button class="card service-link accent-${i%2?'blue':'orange'}" data-go="${id}"><span class="service-number">0${i+1}</span><h2>${title}</h2><p>${desc}</p><b>詳しく見る →</b></button>`).join('')}</div><section class="card customer-flow"><h2>ご相談から運用まで</h2><div class="flow-inline">${['環境確認','比較・提案','制作・設定','動作確認','引渡し・支援'].map((x,i)=>`<span><b>${i+1}</b>${x}</span>`).join('')}</div></section>`}
function positionPage(){return `${pageHead('INFO','私たちの役割','Our Role','サービス提供会社との違いと、対応範囲を明確にご案内します。')}<section class="relationship-diagram"><div><b>PCSAPO マキシ企画</b><span>環境確認・比較・提案・制作・初期設定・運用支援</span></div><strong>＋</strong><div><b>各サービス提供会社・メーカー</b><span>サービス提供・契約・請求・機器保証</span></div><strong>＝</strong><div class="result"><b>店舗に合う導入方法</b><span>予算と実際のオペレーションを優先</span></div></section><div class="grid two">${card('PCSAPOが対応すること','<ul><li>店舗環境とご要望のヒアリング</li><li>複数サービスの比較と組み合わせ提案</li><li>ホームページ・メニュー・設定作業</li><li>初期操作説明と保守・点検</li></ul>','green')}${card('提供会社へ確認すること','<ul><li>各サービスの契約・請求・審査</li><li>サービス障害やアカウント固有の問題</li><li>機器故障・交換・メーカー保証</li><li>公式プランの最終的な利用条件</li></ul>','blue')}</div><section class="card notice"><b>重要：</b>PCSAPO マキシ企画はSTUDIO・Square・funfo各社の代理店、販売店、営業担当者ではありません。公式料金は参考情報として分けて表示し、契約時に各社の公式情報をご確認いただきます。</section>`}
function priceText(item){if(item.priceDisplay==='estimate')return '別途見積';return `${yen(item.price)}${item.priceDisplay==='from'?'〜':''} / ${esc(item.unit)}`}
function catalogSection(group,type,title){const items=visibleCatalog(group,type);if(!items.length)return '';return `<section class="catalog-section"><div class="catalog-section-head"><h2>${title}</h2><span>${type==='official'?'提供会社との直接契約':'PCSAPO作業料金'}</span></div><div class="public-price-list">${items.map(item=>`<article><div><b>${esc(item.name)}</b><p>${esc(item.description||item.notes)}</p>${item.provider?`<small>${esc(item.provider)}</small>`:''}</div><strong>${priceText(item)}</strong>${item.url?`<a href="${esc(item.url)}" target="_blank" rel="noopener">公式情報</a>`:''}</article>`).join('')}</div></section>`}
function serviceDetailPage(group,title,en,lead,features){return `${pageHead('SERVICE',title,en,lead)}<section class="feature-band">${features.map(([name,desc])=>`<div><b>${name}</b><span>${desc}</span></div>`).join('')}</section>${catalogSection(group,'work','制作・導入支援オプション')}${catalogSection(group,'official','公式プラン・機器の参考費用')}<section class="card notice"><b>料金の分け方：</b>PCSAPOの制作・設定料金と、各提供会社へ支払うプラン・機器料金は別です。公式料金は改定される場合があるため、契約前に最新情報を確認します。</section>`}
